import BrandGallery from "./BrandGallery";
import { PHOTOS } from "../data/photos";

const surprisePhotos = PHOTOS.filter((photo) => ["birthday", "anniversary"].includes(photo.category)).slice(0, 9);

export default function AyyanSurpriseGallery({ onBack }) {
  return (
    <BrandGallery
      title="Ayyan Surprises"
      subtitle="Birthday, anniversary and surprise event photography designed to make every moment unforgettable."
      photos={surprisePhotos}
      onBack={onBack}
    />
  );
}
